final:
module RefModule(
    input wire in0,
    input wire in1,
    input wire in2,
    input wire in3,
    input wire [1:0] sel,
    output wire out
);

wire __out_tmp = (sel == 2'b00) ? in0 :
             (sel == 2'b01) ? in1 :
             (sel == 2'b10) ? in2 : in3;
assign out = __out_tmp;

endmodule
